/*
 * This file was generated by the Gradle 'init' task.
 *
 * This project uses @Incubating APIs which are subject to change.
 */

plugins {
    `java-library`
    `maven-publish`
}

repositories {
    mavenLocal()
    maven {
        url = uri("https://central.sonatype.com/repository/maven-snapshots")
    }

    maven {
        url = uri("https://repo.maven.apache.org/maven2/")
    }
}

dependencies {
    testImplementation(libs.org.hibernate.validator.hibernate.validator)
    testImplementation(libs.org.junit.jupiter.junit.jupiter.api)
    testImplementation(libs.org.junit.jupiter.junit.jupiter.params)
    testImplementation(libs.org.hamcrest.hamcrest.all)
    testImplementation(libs.org.mockito.mockito.core)
    compileOnly(libs.com.fasterxml.jackson.core.jackson.databind)
    compileOnly(libs.tools.jackson.core.jackson.databind)
    compileOnly(libs.javax.validation.validation.api)
    compileOnly(libs.jakarta.validation.jakarta.validation.api)
}

group = "org.openapitools"
version = "0.2.9-SNAPSHOT"
description = "JsonNullable Jackson module"
java.sourceCompatibility = JavaVersion.VERSION_1_8

java {
    withSourcesJar()
    withJavadocJar()
}

publishing {
    publications.create<MavenPublication>("maven") {
        from(components["java"])
    }
}

tasks.withType<JavaCompile> {
    options.encoding = "UTF-8"
}

tasks.withType<Javadoc> {
    options.encoding = "UTF-8"
}
